const f   = $input.first().json;
const src = (f['Source Course ID']||'').trim();
const tgt = (f['Target Course ID']||'').trim();
const srcL = (f['Source Language']||'fr').trim();
const tgtL = (f['Target Language']||'en-US').trim();
const dir  = srcL.toLowerCase() + '_' + tgtL.toLowerCase().replace('-','');

const chk = key => !!(Array.isArray(f[key]) ? f[key].length : f[key]);
const REPO = 'https://api.github.com/repos/jeremieborrotzu-blip/Ressources_Loc_OSS/contents';
const out  = '07_runs/' + src + '/output';

return [{json:{
  source_course_id:    src,
  target_course_id:    tgt,
  source_language:     srcL,
  target_language:     tgtL,
  direction:           dir,
  email:               f['Email'],
  process_images:      chk('Process Static Images (PNG/JPG)'),
  process_sheets:      chk('Process Sheets (XLSX/CSV)'),
  process_transcripts: chk('Process Transcripts (SRT/Vimeo)'),
  ui_context:          f['UI Context (optional)']||'',
  html_path:     out + '/' + tgt + '_localized_'        + dir + '.html',
  graphics_path: out + '/' + tgt + '_todo_static_graphics_' + dir + '.csv',
  videos_path:   out + '/' + tgt + '_todo_videos_'      + dir + '.csv',
  log_path:      out + '/' + tgt + '_decision_log_'     + dir + '.json',
  REPO: REPO,
  run_ts: new Date().toISOString()
}}];

const ip = $('Init Params').first().json;
return [{json:{
  email: ip.email,
  subject: 'CLS v3 Media & Annexes — Phase 1 not complete for ' + ip.source_course_id,
  message: 'Phase 1 HTML localization must be complete before running Media & Annexes.\n\n'
    + 'Expected file not found on GitHub:\n' + ip.html_path + '\n\n'
    + 'Steps to fix:\n'
    + '1. Run [MAIN] CLS v3 — Course Localisation with "Localiser le cours (HTML)" checked\n'
    + '2. Wait for PASS status (score ≥ 90) and email confirmation\n'
    + '3. Then relaunch Media & Annexes'
}}];

const ip = $('Init Params').first().json;

function decodeGH(nodeName) {
  try {
    const b64 = $(nodeName).first().json.content;
    if (!b64) return '';
    return Buffer.from(b64.replace(/\n/g,''), 'base64').toString('utf-8');
  } catch(e) { return ''; }
}

function parseCSV(csv) {
  if (!csv.trim()) return [];
  const lines = csv.trim().split('\n');
  if (lines.length < 2) return [];
  const headers = lines[0].split(',').map(h => h.trim().replace(/^"|"$/g,''));
  return lines.slice(1).filter(l => l.trim()).map(line => {
    const vals = line.split(',').map(v => v.trim().replace(/^"|"$/g,''));
    const o = {};
    headers.forEach((h,i) => o[h] = vals[i]||'');
    return o;
  });
}

const html_b64 = (() => { try { return $('Gate: Check Phase 1').first().json.content||''; } catch{return '';} })();
const html_content = Buffer.from(html_b64.replace(/\n/g,''), 'base64').toString('utf-8');

const graphics_csv = decodeGH('Load Graphics CSV');
const videos_csv   = decodeGH('Load Videos CSV');
const log_raw      = decodeGH('Load Decision Log');

let decision_log = {};
try { decision_log = JSON.parse(log_raw); } catch {}

const graphics_rows = parseCSV(graphics_csv);
const videos_rows   = parseCSV(videos_csv);

return [{json:{
  ...ip,
  html_content,
  graphics_rows,
  videos_rows,
  decision_log,
  a2_glossary:     decision_log.a2_glossary || decision_log.unified_terms || [],
  graphics_count:  graphics_rows.length,
  videos_count:    videos_rows.length
}}];

const ip  = $('Init Params').first().json;
const mp1 = $('Merge P1 Outputs').first().json;
const rows = mp1.graphics_rows || [];

// Extract chapter HTML for context (split by h2)
function chapterContext(html, idx) {
  try {
    const sections = html.split(/<h2[^>]*>/i);
    const sec = sections[parseInt(idx)||0 + 1];
    return sec ? ('<h2>' + sec.split(/<h2[^>]*>/i)[0]).substring(0, 4000) : html.substring(0, 2000);
  } catch { return html.substring(0, 2000); }
}

return rows.map(row => ({json:{
  source_course_id:  ip.source_course_id,
  target_course_id:  ip.target_course_id,
  direction:         ip.direction,
  source_language:   ip.source_language,
  target_language:   ip.target_language,
  ui_context:        ip.ui_context,
  a2_glossary:       mp1.a2_glossary,
  img_src:           row.img_src || row.source_value || '',
  alt_text:          row.alt_text || row.anchor_text || '',
  chapter_index:     row.chapter_index || '0',
  image_type:        row.image_type || 'static_graphic',
  action_required:   row.action_required || '',
  chapter_context:   chapterContext(mp1.html_content, row.chapter_index)
}}));

const ip  = $('Init Params').first().json;
const mp1 = $('Merge P1 Outputs').first().json;
let a8_results = [];
try { a8_results = $('A8: Image Localizer (TODO)').all().map(i => i.json); } catch {}
return [{json:{
  ...ip,
  graphics_count:  mp1.graphics_count,
  videos_count:    mp1.videos_count,
  a8_results,
  images_processed: a8_results.length
}}];

